/* Node for sorted linked list of file counts */
struct node {
    char *name;
    struct counts cnts;
    struct node *next;
};

/*
 * Requires:
 *   "input_files" is a valid array of file name strings.
 *   "nfiles" is the number of files in the array.
 *
 * Effects:
 *   Counts characters, words, and/or lines in each file based on flags.
 *   Prints results for each file in ASCIIbetical order.
 *   Prints totals at the end.
 *   Returns 0 on success, 1-255 on error.
 */
static int
do_count(char *input_files[], const int nfiles,
    const bool char_flag, const bool word_flag,
    const bool line_flag, const bool test_flag)
{
    (void)test_flag; /* Suppress unused parameter warning */

    struct counts total = {0, 0, 0};
    struct node *head = NULL;
    int exit_status = 0;

    for (int i = 0; i < nfiles; i++) {
        char *fname = input_files[i];
        FILE *fp = fopen(fname, "r");
        if (fp == NULL) {
            app_error_fmt("cannot open file '%s'", fname);
            exit_status = 1;
            continue;
        }

        struct counts file_cnts = {0, 0, 0};
        int c;
        bool in_word = false;
        bool read_error = false;

        /* Only read if at least one flag is set */
        if (char_flag || word_flag || line_flag) {
            while ((c = fgetc(fp)) != EOF) {
                if (char_flag)
                    file_cnts.chars++;
                if (line_flag && c == '\n')
                    file_cnts.lines++;
                if (word_flag) {
                    if (isspace(c)) {
                        in_word = false;
                    } else if (!in_word) {
                        in_word = true;
                        file_cnts.words++;
                    }
                }
            }
            if (ferror(fp)) {
                app_error_fmt("cannot read file '%s'", fname);
                exit_status = 1;
                read_error = true;
            }
        }
        fclose(fp);

        if (read_error)
            continue;

        /* Update totals only for specified flags */
        if (char_flag)
            total.chars += file_cnts.chars;
        if (word_flag)
            total.words += file_cnts.words;
        if (line_flag)
            total.lines += file_cnts.lines;

        /* Store results for later sorted printing */
        struct node *new_node = malloc(sizeof(struct node));
        if (new_node == NULL) {
            fprintf(stderr, "Error: Memory allocation failed\n");
            exit(1);
        }
        new_node->name = fname;
        new_node->cnts = file_cnts;

        /* Insert into sorted linked list (ASCIIbetical order) */
        struct node **curr = &head;
        while (*curr != NULL && strcmp(new_node->name, (*curr)->name) > 0) {
            curr = &((*curr)->next);
        }
        new_node->next = *curr;
        *curr = new_node;
    }

    /* Print sorted results and free memory */
    struct node *curr = head;
    while (curr != NULL) {
        print_counts(stdout, &curr->cnts, curr->name,
            char_flag, word_flag, line_flag);
        struct node *next = curr->next;
        free(curr);
        curr = next;
    }

    /* Print totals (always print all three counts) */
    print_counts(stdout, &total, "total", true, true, true);

    return exit_status;
}

